#bg {
	pos-x: 1 px;
	pos-y: 1 px;
	position: absolute;
  file: bg.png;
  layer: 0;
}
#leftEye {
	pos-x: 1 px;
	pos-y: 1 px;
	position: relative=bg;
  file: eye.jpg;
  layer: 1;
}
#rightEye {
	pos-x: 4 px;
	pos-y: 0 px;
	position: relative=leftEye;
  file: eye.jpg;
  layer: 1;
}
#nose {
  pos-x: 2 px;
  pos-y: 1 px;
  position: relative=leftEye;
  file: nose.bmp;
  layer: 1;
}
#mouth {
  pos-x: -1 px;
  pos-y: 1 px;
  position: relative = nose;
  file: mouth.png;
  layer: 1;
}
